mapper.insert:
INSERT INTO expenses (
    expense_type, amount, expense_date, description, registered_by
) VALUES (
    #{expenseType}, #{amount}, #{expenseDate}, #{description}, #{registeredBy}
)

INSERT INTO payrolls (
    employee_id, pay_year, pay_month,
    work_hours, base_pay, deduction, net_pay,
    paid_at, note
) VALUES (
    #{employeeId}, #{payYear}, #{payMonth},
    #{workHours}, #{basePay}, #{deduction}, #{netPay},
    #{paidAt}, #{note}
)
